v-loading=\"loading\"\r\n        :title=\"`${activeName == 'expenses' ? 'GASTOS' : 'INGRESOS'}`\"\r\n    >\r\n        <div>\r\n            <el-button\r\n                @click=\"addExpenseIncome\"\r\n                type=\"primary\"\r\n                style=\"margin:8px 0px;\"\r\n            >\r\n                Crear {{ `${activeName == \"expenses\" ? \"Gasto\" : \"Ingreso\"}` }}\r\n            </el-button>\r\n            <el-tabs v-model=\"activeName\" @tab-click=\"handleClick\">\r\n                <el-tab-pane label=\"Gastos\" name=\"expenses\">\r\n                    <expenses-incomes-detail\r\n                        :company=\"company\"\r\n                        @getRecords=\"getRecords\"\r\n                        :records.sync=\"expenses\"\r\n                        :pagination.sync=\"pagination.expenses\"\r\n                        :type=\"'expenses'\"\r\n                    >\r\n                    </expenses-incomes-detail>\r\n                </el-tab-pane>\r\n                <el-tab-pane label=\"Ingresos\" name=\"incomes\">\r\n                    <expenses-incomes-detail\r\n                        :company=\"company\"\r\n                        @getRecords=\"getRecords\"\r\n                        :records.sync=\"incomes\"\r\n                        :pagination.sync=\"pagination.incomes\"\r\n                        :type=\"'incomes'\"\r\n                    >\r\n                    </expenses-incomes-detail>\r\n                    <template v-if=\"activeName == 'expenses'\">\r\n                        <expenses-incomes-form\r\n                            :items_detail.sync=\"items_detail\"\r\n                            :unitTypes.sync=\"unitTypes\"\r\n                            activeName=\"expenses\"\r\n                            :cashid=\"cash_id\"\r\n                            :showDialog.sync=\"showForm\"\r\n                            @getRecords=\"getRecords\"\r\n                            @getItemsDetail=\"getItemsDetail\"\r\n                        >\r\n                        </expenses-incomes-form>\r\n                    </template>\r\n                    <template v-else>\r\n                        <expenses-incomes-form\r\n                            :items_detail.sync=\"items_detail\"\r\n                            :unitTypes=\"unitTypes\"\r\n                            activeName=\"incomes\"\r\n                            :cashid=\"cash_id\"\r\n                            :showDialog.sync=\"showForm\"\r\n                            @getRecords=\"getRecords\"\r\n                            @getItemsDetail=\"getItemsDetail\"\r\n                        >\r\n                        </expenses-incomes-form>\r\n                    </template>\r\n                </el-tab-pane>\r\n            </el-tabs>\r\n        </div>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\nimport ExpensesIncomesDetail from \"./expenses_incomes_detail.vue\";\r\nimport ExpensesIncomesForm from \"./expenses_incomes_form.vue\";\r\nimport queryString from \"query-string\";\r\nexport default {\r\n    components: { ExpensesIncomesDetail, ExpensesIncomesForm },\r\n    props: [\"showDialog\", \"company\", \"cash_id\"],\r\n    data() {\r\n        return {\r\n            time: null,\r\n            loading: false,\r\n            value: null,\r\n            typeSearch: \"document\",\r\n            type: \"expenses\",\r\n            expenses: [],\r\n            items_detail: [],\r\n            unitTypes: [],\r\n            incomes: [],\r\n            pagination: {\r\n                incomes: {},\r\n                expenses: {}\r\n            },\r\n            printer: null,\r\n            lastDocument: null,\r\n            showForm: false,\r\n            activeName: \"expenses\"\r\n        };\r\n    },\r\n    async created() {\r\n        await this.getCashRecords();\r\n        await this.getPrinter();\r\n        await this.getItemsDetail();\r\n        await this.getUnitTypes();\r\n    },\r\n    watch: {\r\n        activeName(oldVal, newVal) {\r\n            this.type = newVal;\r\n        }\r\n    },\r\n    methods: {\r\n        async getUnitTypes() {\r\n            this.loading = true;\r\n            try {\r\n                const response = await this.$http(`/unit_types/records`);\r\n                const {\r\n                    data: { data }\r\n                } = response;\r\n                this.unitTypes = data;\r\n                console.log(this.unitTypes);\r\n            } catch (e) {\r\n                this.$toast.error(\"Error al traer las unidades de medidas\");\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        async getItemsDetail(query = null) {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `/restaurant/items_detail?description=${query ?? \"\"}`\r\n                );\r\n                if (response.status == 200) {\r\n                    const {\r\n                        data: { data }\r\n                    } = response;\r\n                    this.items_detail = data;\r\n                    console.log(this.items_detail);\r\n                }\r\n            } catch (e) {\r\n                this.$toast.error(\"Error al traer los items detalles\");\r\n                console.log(e);\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        },\r\n        addExpenseIncome() {\r\n            this.showForm = true;\r\n        },\r\n        getRecordsInput() {\r\n            this.getRecords();\r\n        },\r\n        async printEvent(url) {\r\n            try {\r\n                let config = qz.configs.create(this.printer, {\r\n                    scaleContent: false\r\n                });\r\n                if (!qz.websocket.isActive()) {\r\n                    await qz.websocket.connect(config);\r\n                }\r\n                let data = [\r\n                    {\r\n                        type: \"pdf\",\r\n                        format: \"file\",\r\n                        data: url\r\n                    }\r\n                ];\r\n                qz.print(config, data).catch(e => {\r\n                    this.$toast.error(e.message);\r\n                });\r\n            } catch (e) {}\r\n        },\r\n\r\n        async getPrinter() {\r\n            this.loading = true;\r\n            const response = await this.$http(\r\n                `cash/get_printer/${this.area_id}`\r\n            );\r\n\r\n            let {\r\n                data: { printer }\r\n            } = response;\r\n            this.printer = printer;\r\n            this.loading = false;\r\n        },\r\n        getRecords(page = 1) {\r\n            if (this.activeName == \"expenses\") {\r\n                this.pagination.expenses.current_page = Number(page);\r\n            } else {\r\n                this.pagination.incomes.current_page = Number(page);\r\n            }\r\n            if (this.time) {\r\n                clearTimeout(this.time);\r\n            }\r\n            this.time = setTimeout(async () => {\r\n                await this.getCashRecords();\r\n            }, 500);\r\n        },\r\n        getQueryParameters(form = {}) {\r\n            return queryString.stringify({\r\n                page:\r\n                    this.activeName == \"expenses\"\r\n                        ? this.pagination.expenses.current_page\r\n                        : this.pagination.incomes.current_page,\r\n                isExpenses: this.activeName == \"expenses\",\r\n                cashId: this.cash_id\r\n\r\n                // limit: this.limit\r\n            });\r\n        },\r\n        handleClick() {\r\n            this.type = this.activeName;\r\n\r\n            if (this.expenses.length == 0 || this.incomes.length == 0) {\r\n                this.getCashRecords();\r\n            }\r\n        },\r\n        async open() {\r\n            this.getCashRecords();\r\n        },\r\n        close() {\r\n            this.$emit(\"update:showDialog\", false);\r\n        },\r\n\r\n        async getCashRecords() {\r\n            try {\r\n                this.loading = true;\r\n                const response = await this.$http(\r\n                    `cash/incomes_expenses?${this.getQueryParameters()}`\r\n                );\r\n\r\n                if (response.status != 200) {\r\n                    this.$toast.error(\"No se pudo obtener los registros\");\r\n                } else {\r\n                    const { data, meta } = response.data;\r\n                    if (this.activeName == \"expenses\") {\r\n                        this.expenses = data;\r\n                        this.pagination.expenses = meta;\r\n                    } else {\r\n                        this.incomes = data;\r\n                        this.pagination.incomes = meta;\r\n                    }\r\n                }\r\n            } catch (e) {\r\n                console.log(e);\r\n                this.$toast.error(\"Error\");\r\n            } finally {\r\n                this.loading = false;\r\n            }\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/expenses_incomes.vue","<template>\r\n    <div v-loading=\"loading\">\r\n        <table class=\"table\">\r\n            <thead>\r\n                <tr>\r\n                    <th>\r\n                        #\r\n                    </th>\r\n                    <th>\r\n                        Motivo\r\n                    </th>\r\n                    <th>Detalle</th>\r\n                    <th>Fecha</th>\r\n                    <th>\r\n                        Total\r\n                    </th>\r\n                </tr>\r\n            </thead>\r\n            <tbody>\r\n                <tr v-for=\"(data, idx) in records\" :key=\"idx\">\r\n                    <td>{{ idx + 1 }}</td>\r\n                    <td>{{ data.description }}</td>\r\n                    <td>\r\n                        <template v-if=\"data.items.length != 0\">\r\n                            <el-button @click=\"seeDetail(data.items)\">\r\n                                <i class=\"fa fa-search\" aria-hidden=\"true\"></i>\r\n                                Ver\r\n                            </el-button>\r\n                        </template>\r\n                    </td>\r\n                    <td>{{ data.date }}</td>\r\n                    <td>{{ data.amount }} <br /></td>\r\n                </tr>\r\n            </tbody>\r\n        </table>\r\n        <el-pagination\r\n            @current-change=\"getRecords\"\r\n            layout=\"total, prev, pager, next\"\r\n            :total=\"pagination.total\"\r\n            :current-page.sync=\"pagination.current_page\"\r\n            :page-size=\"pagination.per_page\"\r\n        ></el-pagination>\r\n        <el-dialog \r\n            append-to-body\r\n            :visible.sync=\"showDetails\">\r\n                <div class=\"p-5\">\r\n            <table class=\"table\">\r\n                                <thead>\r\n                                    <tr>\r\n                                        <th>DESCP.</th>\r\n                                        <th>CANT.</th>\r\n                                        <th>PRECIO UNIT</th>\r\n                                        <th>PRECIO ADICIONAL</th>\r\n                                        <th>PRECIO TOTAL</th>\r\n                                    </tr>\r\n                                </thead>\r\n                                <tbody>\r\n                                    <tr v-for=\"(dt, idx) in currentItems\" :key=\"idx\">\r\n                                        <td>{{ dt.detail }}</td>\r\n                                        <td>\r\n                                            {{ dt.quantity.toFixed(2) }}\r\n                                            {{ dt.unit_id }}\r\n                                        </td>\r\n                                        <td>{{ dt.price.toFixed(2) }}</td>\r\n                                        <td>{{ dt.extra_price.toFixed(2) }}</td>\r\n                                        <td>\r\n                                            {{\r\n                                                (\r\n                                                    dt.price * dt.quantity +\r\n                                                    dt.extra_price\r\n                                                ).toFixed(2)\r\n                                            }}\r\n                                        </td>\r\n                                    \r\n                                        </td>\r\n                                    </tr>\r\n                                </tbody>\r\n                            </table>\r\n            </div>\r\n        </el-dialog>\r\n    </div>\r\n</template>\r\n\r\n<script>\r\nexport default {\r\n    components: {},\r\n    props: [\"records\", \"pagination\", \"type\", \"company\"],\r\n    data() {\r\n        return {\r\n            loading: false,\r\n            showWhatsappModal: false,\r\n            currentId: null,\r\n            currentType: null,\r\n            currentNumber: null,\r\n            currentItems: [],\r\n            showDetails: false\r\n        };\r\n    },\r\n    methods: {\r\n        seeDetail(items) {\r\n            this.currentItems = items;\r\n            this.showDetails = true;\r\n        },\r\n        getRecords() {\r\n            this.$emit(\"getRecords\", this.pagination.current_page);\r\n        }\r\n    }\r\n};\r\n</script>\r\n\n\n\n// WEBPACK FOOTER //\n// modules/Restaurant/Resources/assets/js/views/pos/partials/expenses_incomes_detail.vue","<template>\r\n    <el-dialog\r\n        :title=\"titleDialog\"\r\n        :visible=\"showDialog\"\r\n        @close=\"close\"\r\n        @open=\"create\"\r\n        append-to-body\r\n        width=\"50%\"\r\n        v-loading