                           ></el-input-number>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.amount\"\r\n                                v-text=\"errors.amount[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <div class=\"col-md-4\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.date }\"\r\n                        >\r\n                            <label class=\"control-label\">Fecha</label>\r\n                            <el-date-picker\r\n                                :disabled=\"true\"\r\n                                style=\"width:100%;\"\r\n                                v-model=\"form.date\"\r\n                                format=\"dd-MM-yyyy\"\r\n                                value-format=\"yyyy-MM-dd\"\r\n                                type=\"date\"\r\n                            >\r\n                            </el-date-picker>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.date\"\r\n                                v-text=\"errors.date[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                    <template v-if=\"activeName == 'expenses'\">\r\n                        <div class=\"row\">\r\n                            <div class=\"col-md-4\">\r\n                                <label for=\"item\">\r\n                                    Gasto\r\n                                    <a\r\n                                        href=\"#\"\r\n                                        class=\"control-label font-weight-bold text-info\"\r\n                                        @click=\"openCreateItem\"\r\n                                    >\r\n                                        [ + Nuevo]</a\r\n                                    >\r\n                                </label>\r\n                                <el-select\r\n                                    v-if=\"form.item_add == false\"\r\n                                    v-model=\"detail.item_detail_id\"\r\n                                    filterable\r\n                                    remote\r\n                                    popper-class=\"el-select-customers\"\r\n                                    clearable\r\n                                    placeholder=\"Buscar producto\"\r\n                                    :remote-method=\"searchRemoteItems\"\r\n                                    @change=\"loadDataUtilities\"\r\n                                    class=\"w-100\"\r\n                                >\r\n                                    <el-option\r\n                                        v-for=\"option in items_detail\"\r\n                                        :key=\"option.id\"\r\n                                        :value=\"option.id\"\r\n                                        :label=\"\r\n                                            `${option.detail} ${option.unit_id}`\r\n                                        \"\r\n                                    ></el-option>\r\n                                </el-select>\r\n                                <el-input\r\n                                    placeholder=\"Buscar producto\"\r\n                                    class=\"w-100\"\r\n                                    v-model=\"detail.item_detail_id\"\r\n                                    v-else\r\n                                >\r\n                                </el-input>\r\n                            </div>\r\n                            <div class=\"col-md-2\">\r\n                                <label for=\"qty\">\r\n                                    Cantidad\r\n                                </label>\r\n\r\n                                <el-input-number\r\n                                    controls-position=\"right\"\r\n                                    :controls=\"false\"\r\n                                    :precision=\"2\"\r\n                                    class=\"w-100\"\r\n                                    v-model.number=\"detail.quantity\"\r\n                                ></el-input-number>\r\n                            </div>\r\n                            <div class=\"col-md-2\">\r\n                                <label for=\"price\">\r\n                                    Precio\r\n                                </label>\r\n                                <el-input-number\r\n                                    controls-position=\"right\"\r\n                                    :precision=\"2\"\r\n                                    :controls=\"false\"\r\n                                    class=\"w-100\"\r\n                                    v-model.number=\"detail.price\"\r\n                                ></el-input-number>\r\n                            </div>\r\n                            <div class=\"col-md-2\">\r\n                                <label for=\"price\">\r\n                                    Precio adicional\r\n                                </label>\r\n                                <el-input-number\r\n                                    :min=\"0\"\r\n                                    :precision=\"2\"\r\n                                    class=\"w-100\"\r\n                                    :controls=\"false\"\r\n                                    id=\"extra_price\"\r\n                                    v-model.number=\"detail.extra_price\"\r\n                                ></el-input-number>\r\n                            </div>\r\n                            <div class=\"col-md-2 d-flex align-items-end\">\r\n                                <el-button type=\"primary\" @click=\"addDetail\">\r\n                                    <i\r\n                                        class=\"fa fa-plus\"\r\n                                        aria-hidden=\"true\"\r\n                                    ></i>\r\n                                    Agregar\r\n                                </el-button>\r\n                            </div>\r\n                        </div>\r\n                        <div\r\n                            class=\"row\"\r\n                            style=\"margin-top:25px;\"\r\n                            v-if=\"details != 0\"\r\n                        >\r\n                            <table class=\"table\">\r\n                                <thead>\r\n                                    <tr>\r\n                                        <th>DESCP.</th>\r\n                                        <th>CANT.</th>\r\n                                        <th>PRECIO UNIT</th>\r\n                                        <th>PRECIO ADICIONAL</th>\r\n                                        <th>PRECIO TOTAL</th>\r\n                                        <th>ELIMINAR</th>\r\n                                    </tr>\r\n                                </thead>\r\n                                <tbody>\r\n                                    <tr v-for=\"(dt, idx) in details\" :key=\"idx\">\r\n                                        <td>{{ dt.item.detail }}</td>\r\n                                        <td>\r\n                                            {{ dt.quantity }}\r\n                                            {{ dt.item.unit_id }}\r\n                                        </td>\r\n                                        <td>{{ dt.price }}</td>\r\n                                        <td>{{ dt.extra_price }}</td>\r\n                                        <td>\r\n                                            {{\r\n                                                dt.price * dt.quantity +\r\n                                                    dt.extra_price\r\n                                            }}\r\n                                        </td>\r\n                                        <td>\r\n                                            <el-button\r\n                                                type=\"danger\"\r\n                                                size=\"mini\"\r\n                                                @click=\"\r\n                                                    deleteDetail(\r\n                                                        dt.item_detail_id\r\n                                                    )\r\n                                                \"\r\n                                            >\r\n                                                <i\r\n                                                    class=\"fa fa-trash\"\r\n                                                    aria-hidden=\"true\"\r\n                                                ></i>\r\n                                            </el-button>\r\n                                        </td>\r\n                                    </tr>\r\n                                </tbody>\r\n                            </table>\r\n                        </div>\r\n                    </template>\r\n                    <div class=\"col-md-12 p-2\">\r\n                        <div\r\n                            class=\"form-group\"\r\n                            :class=\"{ 'has-danger': errors.description }\"\r\n                        >\r\n                            <label class=\"control-label\"\r\n                                >Detalle - Concepto</label\r\n                            >\r\n                            <el-input\r\n                                type=\"textarea\"\r\n                                v-model=\"form.description\"\r\n                            >\r\n                                <i\r\n                                    slot=\"prefix\"\r\n                                    class=\"el-icon-edit-outline\"\r\n                                ></i\r\n                            ></el-input>\r\n                            <small\r\n                                class=\"text-danger\"\r\n                                v-if=\"errors.description\"\r\n                                v-text=\"errors.description[0]\"\r\n                            ></small>\r\n                        </div>\r\n                    </div>\r\n                </div>\r\n            </div>\r\n            <div class=\"form-actions text-end pt-2 pb-2\">\r\n                <el-button @click.prevent=\"close()\">Cancelar</el-button>\r\n                <el-button\r\n                    type=\"primary\"\r\n                    native-type=\"submit\"\r\n                    :loading=\"loading_submit\"\r\n                    >Guardar</el-button\r\n                >\r\n            </div>\r\n        </form>\r\n        <el-dialog\r\n            v-loading=\"loading\"\r\n            width=\"50%\"\r\n            append-to-body\r\n            :visible.sync=\"showCreateItem\"\r\n        >\r\n            <div class=\"row p-2\">\r\n                <div class=\"col-md-8\">\r\n                    <label for=\"product\">\r\n                        Descripción\r\n                    </label>\r\n                    <el-input v-model=\"newItem.item\"></el-input>\r\n                </div>\r\n                <div class=\"col-md-4\">\r\n                    <label for=\"type\">\r\n                        Unidad de medida\r\n                    </label>\r\n                    <el-select v-model=\"newItem.unitTypeId\">\r\n                        <el-option\r\n                            v-for=\"(type, idx) in unitTypes\"\r\n                            :key=\"idx\"\r\n                            :value=\"type.id\"\r\n                            :label=\"type.description\"\r\n                        ></el-option>\r\n                    </el-select>\r\n                </div>\r\n                <div class=\"col-12 text-right \" style=\"margin-top:15px;\">\r\n                    <el-button type=\"primary\" @click=\"saveUnitType\"\r\n                        >Guardar</el-button\r\n                    >\r\n                </div>\r\n            </div>\r\n        </el-dialog>\r\n    </el-dialog>\r\n</template>\r\n\r\n<script>\r\n//import { EventBus } from \"../../../helpers/bus\";\r\n\r\nexport default {\r\n    props: [\"cashid\", \"showDialog\", \"activeName\", \"items_detail\", \"unitTypes\"],\r\n    data() {\r\n        return {\r\n            hasDetails: false,\r\n            newItem: {},\r\n            loading_submit: false,\r\n            titleDialog: null,\r\n            loading: false,\r\n            resource: \"restaurant/worker/expenses\",\r\n            errors: {},\r\n            errors_group: {},\r\n            errors_category: {},\r\n            errors_subcategory: {},\r\n            form: {},\r\n            array_subcategorias: [],\r\n            array_categorias: [],\r\n            details: [],\r\n            detail: {\r\n                extra_price: 0\r\n            },\r\n            array_group: [],\r\n            register_group: false,\r\n            register_category: false,\r\n            register_subcategory: false,\r\n            form_group: [],\r\n            form_category: [],\r\n            form_subcategory: [],\r\n            array_company: [],\r\n            payment_methods: [],\r\n            showCreateItem: false\r\n        };\r\n    },\r\n    watch: {},\r\n    created() {\r\n        this.initForm();\r\n        this.$http.get(`/${this.resource}/tables`).then(response => {\r\n            this.array_group = response.data.gruop;\r\n            this.array_categorias = response.data.category;\r\n            this.array_subcategorias = response.data.subcategory;\r\n            this.array_company = response.data.company;\r\n            this.payment_methods = response.data.methods;\r\n     